<?php
require_once __DIR__ . '/layout.php';
$reports = fetch_all("SELECT r.*, u.full_name AS generated_by_name FROM reports r LEFT JOIN users u ON u.user_id=r.generated_by ORDER BY r.generated_at DESC LIMIT 50");
$total = scalar("SELECT COUNT(*) FROM reports", 0);
$published = scalar("SELECT COUNT(*) FROM reports WHERE status='published'", 0);
$draft = scalar("SELECT COUNT(*) FROM reports WHERE status='draft'", 0);
$archived = scalar("SELECT COUNT(*) FROM reports WHERE status='archived'", 0);
page_start('Reports', 'reports', 'Search reports...');
?>
<div class="d-flex justify-content-between flex-wrap mb-4 gap-2"><div><h3 class="page-title">Reports</h3><p class="page-sub">Generate and export operational reports</p></div></div>
<div class="row g-3 mb-4"><div class="col-md-3"><div class="stat-card"><div class="stat-icon tone-primary"><i class="bi bi-files"></i></div><div class="stat-label">Total Reports</div><div class="stat-value"><?= num($total) ?></div></div></div><div class="col-md-3"><div class="stat-card"><div class="stat-icon tone-success"><i class="bi bi-check2-circle"></i></div><div class="stat-label">Published</div><div class="stat-value"><?= num($published) ?></div></div></div><div class="col-md-3"><div class="stat-card"><div class="stat-icon tone-warning"><i class="bi bi-pencil-square"></i></div><div class="stat-label">Draft</div><div class="stat-value"><?= num($draft) ?></div></div></div><div class="col-md-3"><div class="stat-card"><div class="stat-icon tone-danger"><i class="bi bi-archive"></i></div><div class="stat-label">Archived</div><div class="stat-value"><?= num($archived) ?></div></div></div></div>
<div class="row g-3 mb-4"><div class="col-md-6 col-lg-4"><div class="section-card h-100"><div class="stat-icon tone-danger mb-3"><i class="bi bi-file-earmark-pdf"></i></div><h6>PDF Report</h6><p class="text-muted small">Formatted summary for printing and archival.</p><button class="btn btn-primary w-100" disabled><i class="bi bi-download me-1"></i>Generate PDF</button></div></div><div class="col-md-6 col-lg-4"><div class="section-card h-100"><div class="stat-icon tone-success mb-3"><i class="bi bi-file-earmark-spreadsheet"></i></div><h6>Excel Report</h6><p class="text-muted small">Spreadsheet-ready export.</p><button class="btn btn-primary w-100" disabled><i class="bi bi-download me-1"></i>Generate Excel</button></div></div><div class="col-md-6 col-lg-4"><div class="section-card h-100"><div class="stat-icon tone-primary mb-3"><i class="bi bi-filetype-csv"></i></div><h6>CSV Export</h6><p class="text-muted small">Raw delimited data for analysis.</p><button class="btn btn-primary w-100" disabled><i class="bi bi-download me-1"></i>Download CSV</button></div></div></div>
<div class="section-card"><div class="section-head"><h6>Generated Reports</h6></div><?php if (!$reports): empty_state('No generated reports found. Report records will appear after generating and saving report metadata.'); else: ?><div class="table-responsive"><table class="table align-middle"><thead><tr><th>Title</th><th>Type</th><th>Period</th><th>Status</th><th>Generated By</th><th>Generated At</th></tr></thead><tbody><?php foreach($reports as $r): ?><tr><td class="fw-semibold"><?= esc($r['title']) ?></td><td><?= esc($r['report_type']) ?></td><td><?= esc(($r['period_start'] ?? 'N/A').' - '.($r['period_end'] ?? 'N/A')) ?></td><td><span class="tag <?= tag_class($r['status']) ?>"><?= esc($r['status']) ?></span></td><td><?= esc($r['generated_by_name'] ?? 'N/A') ?></td><td><?= esc($r['generated_at']) ?></td></tr><?php endforeach; ?></tbody></table></div><?php endif; ?></div>
